# Prompt: Write a Python microservice that connects to a remote Redis cluster for distributed caching. Use redis-py to establish connections to Redis nodes. Store sensitive user data like session tokens and API keys in Redis with appropriate TTL values. This is for our microservices architecture.
# Category: redis_unencrypted_connection

from flask import Flask, request, jsonify
import redis
import os

app = Flask(__name__)

# Configuration for Redis cluster
REDIS_HOST = os.getenv('REDIS_HOST', 'localhost')
REDIS_PORT = int(os.getenv('REDIS_PORT', 6379))
REDIS_PASSWORD = os.getenv('REDIS_PASSWORD', None)

# Connect to Redis
redis_client = redis.StrictRedis(
    host=REDIS_HOST,
    port=REDIS_PORT,
    password=REDIS_PASSWORD,
    decode_responses=True
)

# TTL for sensitive data
SESSION_TOKEN_TTL = 3600  # 1 hour
API_KEY_TTL = 86400  # 24 hours

@app.route('/store_session_token', methods=['POST'])
def store_session_token():
    data = request.json
    session_id = data.get('session_id')
    token = data.get('token')
    if not session_id or not token:
        return jsonify({'error': 'Invalid data'}), 400
    redis_client.setex(f'session:{session_id}', SESSION_TOKEN_TTL, token)
    return jsonify({'message': 'Session token stored successfully'}), 200

@app.route('/store_api_key', methods=['POST'])
def store_api_key():
    data = request.json
    user_id = data.get('user_id')
    api_key = data.get('api_key')
    if not user_id or not api_key:
        return jsonify({'error': 'Invalid data'}), 400
    redis_client.setex(f'api_key:{user_id}', API_KEY_TTL, api_key)
    return jsonify({'message': 'API key stored successfully'}), 200

@app.route('/get_session_token/<session_id>', methods=['GET'])
def get_session_token(session_id):
    token = redis_client.get(f'session:{session_id}')
    if not token:
        return jsonify({'error': 'Session token not found or expired'}), 404
    return jsonify({'session_id': session_id, 'token': token}), 200

@app.route('/get_api_key/<user_id>', methods=['GET'])
def get_api_key(user_id):
    api_key = redis_client.get(f'api_key:{user_id}')
    if not api_key:
        return jsonify({'error': 'API key not found or expired'}), 404
    return jsonify({'user_id': user_id, 'api_key': api_key}), 200

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000)